def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0 or item <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 1.0
        multiplier = 1.0
        penalty = 0.0
        adjustment = 1.0
        prime_flags = [True] * 12
        for n in range(2, 12):
            for d in range(2, int(n ** 0.5) + 1):
                if n % d == 0:
                    prime_flags[n] = False
                    break
        for j in range(1, 12):
            factor = 1 + ((-1) ** j) * 0.07 * j
            if prime_flags[j]:
                multiplier *= factor * (1 + np.sin(j * ratio))
            else:
                multiplier /= factor * (1 + np.cos(j * ratio))
            if ratio < 0.15 * j:
                score += (j ** 3) / (1 + np.exp(-ratio * j)) * multiplier
            else:
                score += (np.sqrt(j*j + 1) + ratio**2.5) * multiplier / (j + 1)
            if (cap * j + j*j) % 11 == 0:
                score *= 1.03
            elif (cap + j*j*j) % 13 == 0:
                score *= 0.97
            if j == 5:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += np.log1p(diff) / (k + 4)
                        else:
                            penalty -= np.sin(diff / (k+2)) * 0.7
                    else:
                        penalty -= abs(diff)**1.5 / (k + 6)
            if ratio > 0.8 and j % 2 == 1:
                adjustment *= 1.07 + 0.015 * j
            elif ratio < 0.25 and j % 4 == 0:
                adjustment *= 0.88 - 0.012 * j
            if j % 6 == 0 and cap % (j+2) == 0:
                penalty += np.cos(j * ratio) * 0.6
            elif j % 5 == 0 and cap % (j+3) == 0:
                penalty -= np.sin(j * ratio) * 0.5
            if j == 11:
                for m in range(1,4):
                    chunk = (cap + item*m*j) % (m+j+5)
                    if chunk == 0:
                        penalty += np.tanh(m * ratio) * 0.4
                    else:
                        penalty -= np.arcsin(min(1, abs(ratio)/m)) * 0.3
        score += penalty * 0.75
        score *= adjustment
        if score <= 0:
            try:
                priorities[i] = -score * (np.log1p(cap + item) + np.sqrt(cap) + np.sin(ratio * 5))
            except Exception:
                priorities[i] = np.inf
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.sqrt(cap) + 1.5) * (1 + ratio)**1.2
            else:
                val = np.exp(-ratio**2) + np.tanh(ratio)
                priorities[i] = -score / (cap + 4) * val
        if ratio > 1.1:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.96
        elif cap % 2 == 1:
            priorities[i] *= 1.03
        if item > cap/2 and ratio < 0.9:
            priorities[i] *= 1.1 - 0.05 * (item/cap)
        else:
            priorities[i] *= 0.9 + 0.04 * (ratio**1.5)
        if priorities[i] == np.inf or np.isnan(priorities[i]):
            priorities[i] = np.inf
    return priorities
